const client = $input.item.json;
const fields = client.fields || {};

const clientName  = fields['Client Name'] || 'Client';
const whatsappNum = fields['WhatsApp Number'] || '';
const kundliRaw   = fields['kundli_json'] || '';

let kundli = {};
try {
  kundli = typeof kundliRaw === 'string' ? JSON.parse(kundliRaw) : (kundliRaw || {});
} catch(e) {
  kundli = {};
}

const rashi      = fields['Rashi']             || kundli?.personal_info?.moon_sign              || 'Unknown';
const nakshatra  = fields['Nakshatra']         || kundli?.personal_info?.nakshatra              || 'Unknown';
const lagna      = fields['Lagna']             || kundli?.personal_info?.ascendant              || 'Unknown';
const mahadasha  = fields['Current Mahadasha'] || kundli?.dasha_periods?.current_mahadasha?.planet  || 'Unknown';
const antardasha = fields['Current Antardasha']|| kundli?.dasha_periods?.current_antardasha?.planet || 'Unknown';
const luckyColor  = fields['Lucky Color']  || '';
const luckyNumber = fields['Lucky Number'] || '';

// Detect timezone from WhatsApp number
const whatsNum = String(fields['WhatsApp Number'] || '');
let clientTZ = 'Asia/Kolkata';
if (whatsNum.startsWith('+1'))       clientTZ = 'America/Toronto';
else if (whatsNum.startsWith('+44'))  clientTZ = 'Europe/London';
else if (whatsNum.startsWith('+61'))  clientTZ = 'Australia/Sydney';
else if (whatsNum.startsWith('+971')) clientTZ = 'Asia/Dubai';
else if (whatsNum.startsWith('+65'))  clientTZ = 'Asia/Singapore';
const today = $now.setZone(clientTZ).toFormat('cccc, MMMM dd, yyyy');

const prompt = `You are a senior Vedic Jyotishi writing a private daily note to your client. 
Speak as a real astrologer — authoritative, warm, precise. No apps, no bots, no templates.

CLIENT: ${clientName}
TODAY: ${today}

CHART DETAILS:
- Lagna: ${lagna}
- Rashi: ${rashi}
- Nakshatra: ${nakshatra}
- Running Dasha: ${mahadasha} / ${antardasha}
- Lucky Colour: ${luckyColor}
- Lucky Number: ${luckyNumber}

FULL KUNDLI:
${kundliRaw ? JSON.stringify(kundli, null, 2).slice(0, 3000) : 'Not available'}

Write today's muhurat guidance as plain WhatsApp text. Structure:

Line 1: "Pranam ${clientName}," 
Line 2: One sentence on today's planetary energy specific to their chart — name the exact nakshatra lord or dasha planet at work.
Auspicious window: State the best 2-hour window today and why (cite nakshatra or transit).
Good for: Two or three activities favoured by today's energy, grounded in their chart.
Caution: One thing to avoid and the astrological reason.
Lucky: Colour and number for today.
Remedy: One simple, specific act tied to the dasha planet lord. Classical remedy — not generic.
Close with: "Jai Shri Ganesh."

RULES:
- No emoji. No bullet points. No headings. No asterisks.
- Write in flowing sentences, the way a Jyotishi dictates to a client.
- Cite specific chart factors — nakshatra pada, dasha lord, rashi.
- Under 130 words total.
- Sound like a person, not an app.`;

return {
  json: {
    prompt,
    clientName,
    whatsappNumber: whatsappNum,
    recordId: client.id
  }
};
